import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Call API","description":"","frontmatter":{},"headers":[],"relativePath":"guide/call.md","filePath":"guide/call.md","lastUpdated":1776985505000}'),i={name:"guide/call.md"};function s(r,e,d,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="call-api" tabindex="-1">Call API <a class="header-anchor" href="#call-api" aria-label="Permalink to &quot;Call API&quot;">​</a></h1><p>EasyYapi supports sending API requests directly from IDEA for quick testing and debugging.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><ol><li>Open a file containing APIs in your project</li><li>Click the gutter icon (▶) next to an API method to open it in the API Dashboard</li><li>Configure request parameters (host, headers, body, etc.)</li><li>Click <strong>Send</strong> to execute the request</li></ol><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><h3 id="pre-request-callback" tabindex="-1">Pre-request Callback <a class="header-anchor" href="#pre-request-callback" aria-label="Permalink to &quot;Pre-request Callback&quot;">​</a></h3><p>Use <code>http.call.before</code> to execute custom logic before sending a request:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">http.call.before</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">it.header(&quot;Authorization&quot;, &quot;Bearer &quot; + localStorage.get(&quot;token&quot;))</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span></code></pre></div><h3 id="post-request-callback" tabindex="-1">Post-request Callback <a class="header-anchor" href="#post-request-callback" aria-label="Permalink to &quot;Post-request Callback&quot;">​</a></h3><p>Use <code>http.call.after</code> to execute custom logic after receiving a response:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">http.call.after</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">if (it.response().code() == 200) {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    def body = it.response().body()</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    localStorage.set(&quot;token&quot;, body.token)</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span></code></pre></div><p>See <a href="/settings/rules/http_call_before">http.call.before</a> and <a href="/settings/rules/http_call_after">http.call.after</a> for more details.</p><h2 id="grpc-call" tabindex="-1">gRPC Call <a class="header-anchor" href="#grpc-call" aria-label="Permalink to &quot;gRPC Call&quot;">​</a></h2><p>EasyYapi also supports calling gRPC methods directly from the IDE. This feature is disabled by default; enable it in IDE settings:</p><p><kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd> &gt; <kbd>gRPC</kbd></p><p>Check the <strong>Enable gRPC call</strong> checkbox to enable gRPC call support.</p><p>When gRPC call is enabled, the plugin needs gRPC runtime JARs to invoke methods. You can configure the runtime dependencies via:</p><ul><li><strong>IDE Settings</strong>: Use the <strong>Auto Detect</strong> button in <kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd> &gt; gRPC Runtime to automatically detect and resolve dependencies.</li></ul><p>See <a href="/framework/grpc">gRPC Framework Support</a> for more details on gRPC configuration.</p><h2 id="gutter-icon-navigation" tabindex="-1">Gutter Icon Navigation <a class="header-anchor" href="#gutter-icon-navigation" aria-label="Permalink to &quot;Gutter Icon Navigation&quot;">​</a></h2><p>EasyYapi adds a gutter icon (▶) next to API methods in the editor. Clicking this icon opens the <strong>API Dashboard</strong> and navigates directly to the corresponding endpoint.</p><h3 id="supported-annotations" tabindex="-1">Supported Annotations <a class="header-anchor" href="#supported-annotations" aria-label="Permalink to &quot;Supported Annotations&quot;">​</a></h3><p>The gutter icon appears on methods annotated with:</p><table tabindex="0"><thead><tr><th>Framework</th><th>Annotations</th></tr></thead><tbody><tr><td>Spring MVC</td><td><code>@RequestMapping</code>, <code>@GetMapping</code>, <code>@PostMapping</code>, <code>@PutMapping</code>, <code>@DeleteMapping</code>, <code>@PatchMapping</code></td></tr><tr><td>JAX-RS</td><td><code>@GET</code>, <code>@POST</code>, <code>@PUT</code>, <code>@DELETE</code>, <code>@PATCH</code>, <code>@Path</code></td></tr><tr><td>gRPC</td><td>RPC methods in classes extending <code>BindableService</code> or annotated with <code>@GrpcService</code></td></tr></tbody></table><h3 id="auto-re-scan" tabindex="-1">Auto Re-scan <a class="header-anchor" href="#auto-re-scan" aria-label="Permalink to &quot;Auto Re-scan&quot;">​</a></h3><p>If the endpoint is not found in the current index (e.g., after a branch switch or when the file is new), clicking the gutter icon automatically triggers a re-scan of the containing file before navigating to the dashboard.</p><h2 id="api-dashboard" tabindex="-1">API Dashboard <a class="header-anchor" href="#api-dashboard" aria-label="Permalink to &quot;API Dashboard&quot;">​</a></h2><p>EasyYapi provides an <strong>API Dashboard</strong> tool window for browsing, testing, and managing API endpoints. Open it from the bottom tool window bar in IDEA.</p><h3 id="browsing-endpoints" tabindex="-1">Browsing Endpoints <a class="header-anchor" href="#browsing-endpoints" aria-label="Permalink to &quot;Browsing Endpoints&quot;">​</a></h3><p>The dashboard displays all detected API endpoints in a tree view organized by module and class:</p><ul><li><strong>Color-coded methods</strong>: HTTP methods are color-coded (GET=blue, POST=green, PUT=orange, DELETE=red, PATCH=cyan) and gRPC endpoints are shown in purple with streaming type indicators (<code>gRPC:U</code> for Unary, <code>gRPC:S</code> for Server Streaming, <code>gRPC:C</code> for Client Streaming, <code>gRPC:B</code> for Bidirectional)</li><li><strong>Search</strong>: Type in the search field to filter endpoints by name, path, folder, description, or class name (case-insensitive, with debounced input)</li><li><strong>Toolbar actions</strong>: Refresh, Export, Collapse All, Expand All</li></ul><h3 id="endpoint-details" tabindex="-1">Endpoint Details <a class="header-anchor" href="#endpoint-details" aria-label="Permalink to &quot;Endpoint Details&quot;">​</a></h3><p>Selecting an endpoint in the tree opens the details panel on the right, which includes:</p><ul><li><strong>Request line</strong>: HTTP method, host URL (with history), path, Send and Reset buttons</li><li><strong>Tabbed parameter editor</strong>: <ul><li><strong>Path</strong> — Path parameters (e.g., <code>/users/{id}</code>)</li><li><strong>Params</strong> — Query string and cookie parameters</li><li><strong>Headers</strong> — Request headers</li><li><strong>Form</strong> — Form data parameters (for <code>application/x-www-form-urlencoded</code> or <code>multipart/form-data</code>)</li><li><strong>Body</strong> — JSON request body (with syntax highlighting)</li></ul></li><li><strong>Response panel</strong>: Status code, response body (with Pretty/Raw JSON toggle and Copy button), and response headers</li></ul><h3 id="sending-requests" tabindex="-1">Sending Requests <a class="header-anchor" href="#sending-requests" aria-label="Permalink to &quot;Sending Requests&quot;">​</a></h3><ol><li>Select an endpoint in the tree</li><li>Configure the host, parameters, headers, and body as needed</li><li>Click <strong>Send</strong> to execute the request</li><li>View the response in the panel below</li></ol><p>For gRPC endpoints, the dashboard checks that gRPC call is enabled and runtime dependencies are available before sending. If not configured, it prompts you to open the settings.</p><h3 id="context-menu" tabindex="-1">Context Menu <a class="header-anchor" href="#context-menu" aria-label="Permalink to &quot;Context Menu&quot;">​</a></h3><p>Right-click on endpoints or folders in the tree to access:</p><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><strong>Export</strong></td><td>Export selected endpoints to Markdown, YApi, Postman, cURL, or HttpClient</td></tr><tr><td><strong>Copy Path</strong></td><td>Copy the endpoint path to clipboard</td></tr><tr><td><strong>Copy as cURL</strong></td><td>Copy a cURL command for the endpoint to clipboard</td></tr><tr><td><strong>Navigate to Source</strong></td><td>Jump to the source code of the endpoint</td></tr><tr><td><strong>Reset to Default</strong></td><td>Reset any user modifications to the default values</td></tr></tbody></table><p>Double-click an endpoint to navigate directly to its source code.</p><h3 id="auto-save" tabindex="-1">Auto-save <a class="header-anchor" href="#auto-save" aria-label="Permalink to &quot;Auto-save&quot;">​</a></h3><p>User modifications to request parameters, headers, host, and body are automatically saved and restored when you revisit the same endpoint.</p>`,43)])])}const u=t(i,[["render",s]]);export{g as __pageData,u as default};
